32: public class HibernateSessionFactory {
33: 
34: 	private final ThreadLocal<Session> sessionThreadLocal = new ThreadLocal<Session>();
35: 
36: 	private SessionFactory sessionFactory;
37: 
38: 	private Configuration configuration;
39: 
40: 	public HibernateSessionFactory() {
41: 		this.configuration = new HibernateConfiguration();
42: 		configuration.configure();
43: 		this.sessionFactory = this.buildSessionFactory(configuration);
44: 	}
45: 
46: 	public HibernateSessionFactory(Configuration configuration) {
47: 		this.configuration = configuration;
48: 		configuration.configure();
49: 		this.sessionFactory = this.buildSessionFactory(configuration);
50: 	}
51: 
52: 	public SessionFactory getSessionFactory() {
53: 		return this.sessionFactory;
54: 	}
55: 
56: 	public void rebuildSessionFactory() {
57: 		if (configuration instanceof HibernateConfiguration) {
58: 			HibernateConfiguration hibernateConfiguration = (HibernateConfiguration) this.configuration;
59: 			this.configuration.configure(hibernateConfiguration.getHibernateConfigFile());
60: 		} else {
61: 			this.configuration.configure();
62: 		}
63: 		this.sessionFactory = this.buildSessionFactory(configuration);
64: 	}
65: 
66: 	public Session getSession() {
67: 		Session session = this.sessionThreadLocal.get();
68: 		if (session == null || (!session.isOpen())) {
69: 			if (this.sessionFactory == null) {
70: 				rebuildSessionFactory();
71: 			}
72: 			session = this.sessionFactory.openSession();
73: 			this.sessionThreadLocal.set(session);
74: 		}
75: 		return session;
76: 	}
77: 
78: 	public void closeSession() throws HibernateException {
79: 		Session session = this.sessionThreadLocal.get();
80: 		if (session != null) {
81: 			session.close();
82: 		}
83: 		this.sessionThreadLocal.set(null);
84: 	}
85: 
86: 	private SessionFactory buildSessionFactory(Configuration configuration) {
87: 		ServiceRegistry serviceRegistry =
88: 			new StandardServiceRegistryBuilder().applySettings(configuration.getProperties()).build();
89: 		return configuration.buildSessionFactory(serviceRegistry);
90: 	}
91: }

